c
// Consistency check pattern
while (true) {
// Load pointer
tail = atomic_load_explicit(
&queue->tail,
memory_order_acquire);
// Dereference (RACE WINDOW)
next = atomic_load_explicit(
&tail->next,
memory_order_acquire);
// VALIDATION: Re-read and compare
if (tail != atomic_load_explicit(
&queue->tail,
memory_order_acquire)) {
continue; // Retry - tail changed
}
// tail is still valid, proceed...
break;
}
